+/// Returns true if `expr` contains an aggregate that must never return NULL
+/// (`count`, `total`).
+fn expr_contains_never_null_agg(expr: &Expr) -> bool {
+    match expr {
+        Expr::FunctionCall { name, args, .. } => {
+            let lower = name.to_ascii_lowercase();
+            if (lower == "total" || lower == "count") && !is_scalar_max_min(name, args) {
+                return true;
+            }
+            match args {
+                FunctionArgs::List(exprs) => exprs.iter().any(expr_contains_never_null_agg),
+                FunctionArgs::Star => lower == "count",
+            }
+        }
+        Expr::BinaryOp { left, right, .. } => {
+            expr_contains_never_null_agg(left) || expr_contains_never_null_agg(right)
+        }
+        Expr::UnaryOp { expr: inner, .. } | Expr::Cast { expr: inner, .. } => {
+            expr_contains_never_null_agg(inner)
+        }
+        _ => false,
+    }
+}
+
+/// Evaluate an expression tree for the empty-set aggregate case,
+/// substituting aggregate calls with their empty-set defaults.
+fn eval_empty_set_agg_expr(expr: &Expr) -> SqliteValue {
+    match expr {
+        Expr::FunctionCall { name, args, .. } if is_agg_fn(name) && !is_scalar_max_min(name, args) => {
+            empty_aggregate_default(&name.to_ascii_lowercase())
+        }
+        Expr::FunctionCall { name, args, .. } => {
+            // Scalar wrapper like typeof(total(val)): evaluate inner args
+            // and apply the scalar function.
+            let lower = name.to_ascii_lowercase();
+            if lower == "typeof" {
+                if let FunctionArgs::List(exprs) = args {
+                    if let Some(inner) = exprs.first() {
+                        let inner_val = eval_empty_set_agg_expr(inner);
+                        let type_str = match &inner_val {
+                            SqliteValue::Null => "null",
+                            SqliteValue::Integer(_) => "integer",
+                            SqliteValue::Float(_) => "real",
+                            SqliteValue::Text(_) => "text",
+                            SqliteValue::Blob(_) => "blob",
+                        };
+                        return SqliteValue::Text(type_str.into());
+                    }
+                }
+            }
+            // For other scalar wrappers, fall back to NULL.
+            SqliteValue::Null
+        }
+        _ => SqliteValue::Null,
+    }
+}
